    const { data, loading, error } = useData()
    const treeData = useTreeStore((state) => state.treeData)
    const setTreeData = useTreeStore((state) => state.setTreeData)
    useEffect(() => {
        if (data) {
            setTreeData(data)
        }
    }, [data])
    return (
        <>
            Hooked!
